@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
    font-family: 'Inter', system-ui, sans-serif;
  }
}

@layer components {
  .font-inter {
    font-family: 'Inter', system-ui, sans-serif;
  }

  .logo-text {
    font-size: 2rem;
    font-weight: 700;
    color: var(--addypin-dark);
    letter-spacing: -0.025em;
  }

  .logo-pin {
    display: inline-block;
    width: 20px;
    height: 20px;
    background: #00BCD4;
    border-radius: 50% 50% 50% 0;
    transform: rotate(-45deg);
    position: relative;
    margin: 0 4px;
    border: 2px solid white;
    box-shadow: 0 2px 6px rgba(0, 188, 212, 0.3);
  }

  .logo-pin::after {
    content: '';
    position: absolute;
    width: 6px;
    height: 6px;
    background: white;
    border-radius: 50%;
    top: 4px;
    left: 4px;
    transform: rotate(45deg);
  }

  .stats-card {
    background: linear-gradient(135deg, #ffffff 0%, #f8fafc 100%);
    border: 1px solid #e2e8f0;
  }
}

@layer utilities {
  .text-addypin-cyan {
    color: var(--addypin-cyan);
  }

  .text-addypin-dark {
    color: var(--addypin-dark);
  }

  .text-addypin-medium {
    color: var(--addypin-medium);
  }

  .bg-addypin-cyan {
    background-color: var(--addypin-cyan);
  }

  .bg-addypin-light {
    background-color: var(--addypin-light);
  }

  .border-addypin-cyan {
    border-color: var(--addypin-cyan);
  }

  .hover\:bg-addypin-cyan:hover {
    background-color: var(--addypin-cyan);
  }

  .hover\:text-addypin-cyan:hover {
    color: var(--addypin-cyan);
  }

  .hover\:text-addypin-dark:hover {
    color: var(--addypin-dark);
  }

  .hover\:border-addypin-cyan:hover {
