import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { useStats } from "@/hooks/useStats";
import { useAuth } from "@/hooks/useAuth";
import { Link } from "wouter";
import { Lock, Unlock } from "lucide-react";
import AddyPinIcon from "./AddyPinIcon";
import { SignInButton } from '@clerk/clerk-react';
import AuthHeader from "./AuthHeader";

interface SidebarProps {
  coordinates: { lat: number; lng: number } | null;
  generatedLink: { webLink: string; emailLink: string } | null;
  onLinkGenerated: (link: { webLink: string; emailLink: string }) => void;
  isMapWidth?: boolean;
}

export default function Sidebar({ coordinates, generatedLink, onLinkGenerated, isMapWidth = false }: SidebarProps) {
  const [email, setEmail] = useState("");
  const [otpCode, setOtpCode] = useState("");
  const [editToken, setEditToken] = useState("");
  const [showOtpInput, setShowOtpInput] = useState(false);
  const { toast } = useToast();
  const { data: stats, isLoading: statsLoading } = useStats();

  const generatePinMutation = useMutation({
    mutationFn: async () => {
      if (!coordinates) throw new Error("No coordinates set");

      const response = await apiRequest("POST", "/api/pins", {
        latitude: coordinates.lat.toString(),
        longitude: coordinates.lng.toString(),
        shortcode: "", // Will be generated by server
        createdBy: email || undefined, // Optional email
      });
      return response.json();
    },
    onSuccess: (data) => {
      onLinkGenerated({
        webLink: data.webLink,
        emailLink: data.emailLink,
      });
      // Trigger pin list refresh if user is authenticated and has matching email
      if (data.createdBy) {
        window.dispatchEvent(new CustomEvent('pinCreated', { 
          detail: { createdBy: data.createdBy } 
        }));
      }
      toast({
        title: "addypin generated!",
        description: "Your short link is ready to share.",
      });
    },
    onError: async (error) => {
      // Check if it's a PIN_LIMIT_EXCEEDED error
      if (error instanceof Error && error.message.includes("PIN_LIMIT_EXCEEDED")) {
        toast({
          title: "addypin limit reached",
          description: "You have reached the 5 addypin limit for this email. Please delete some addypins to create new ones.",
          variant: "destructive",

        });
      } else {
        toast({
          title: "Error", 
          description: error instanceof Error ? error.message : "Failed to generate link",
          variant: "destructive",
        });
      }
    },
  });

  const sendOtpMutation = useMutation({
    mutationFn: async (email: string) => {
      const response = await apiRequest("POST", "/api/otp/send", { email });
      return response.json();
    },
    onSuccess: (data, email) => {
      setShowOtpInput(true);

      // Check message to determine if email was sent successfully
      if (data.message.includes('sent to your email')) {
        // Actual email sent
        toast({
          title: "Verification Code Sent",
          description: "Check your email for the 6-digit verification code",
          duration: 5000,
        });
      } else {
        // Console fallback mode
        toast({
          title: "Verification Code Sent",
          description: data.message,
          duration: 8000,
        });
        console.log(`\n🔑 ===============================`);
        console.log(`🔑 CHECK SERVER CONSOLE ABOVE FOR OTP CODE`);
        console.log(`🔑 EMAIL: ${email.toUpperCase()}`);
        console.log(`🔑 ===============================\n`);
      }
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Failed to send OTP",
        variant: "destructive",
      });
    },
  });

  const verifyOtpMutation = useMutation({
    mutationFn: async ({ email, code }: { email: string; code: string }) => {
      const response = await apiRequest("POST", "/api/otp/verify", { email, code });
      return response.json();
    },
    onSuccess: (data) => {
      setEditToken(data.editToken);
      toast({
        title: "Verified",
        description: "You can now edit addypin coordinates",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Invalid OTP",
        variant: "destructive",
      });
    },
  });

  const sendEmailMutation = useMutation({
    mutationFn: async () => {
      if (!coordinates || !email) throw new Error("Missing coordinates or email");

      const response = await apiRequest("POST", "/api/send-location", {
        email,
        latitude: coordinates.lat.toString(),
        longitude: coordinates.lng.toString(),
        shortcode: generatedLink ? generatedLink.webLink.split('.')[0] : undefined,
      });
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Email Sent!",
        description: "Location details have been sent to your email.",
      });
      setEmail("");
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error instanceof Error ? error.message : "Failed to send email",
        variant: "destructive",
      });
    },
  });

  const copyToClipboard = async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      toast({
        title: "Copied!",
        description: "Link copied to clipboard.",
      });
    } catch (err) {
      toast({
        title: "Error",
        description: "Failed to copy to clipboard.",
        variant: "destructive",
      });
    }
  };

  return (
    <div className="lg:col-span-1 space-y-6">
      {/* Short Link Generator */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <h2 className="text-lg font-semibold text-addypin-dark mb-4 flex items-center">
          <AddyPinIcon className="text-addypin-cyan mr-3" size={20} />
          Generate addypin!
        </h2>

        <div className="space-y-4">
          {/* Honeypot field - hidden from users */}
          <input
            type="text"
            name="website"
            style={{ display: 'none' }}
            tabIndex={-1}
            autoComplete="off"
            aria-hidden="true"
          />

          <div>
            <Label htmlFor="creator-email" className="block text-sm font-medium text-addypin-dark mb-2">
              Associate with email (optional)
            </Label>
            <Input
              id="creator-email"
              type="email"
              placeholder="your@email.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="border-gray-300 focus:border-addypin-cyan focus:ring-addypin-cyan placeholder:text-gray-400"
              data-testid="input-creator-email"
            />
            <p className="text-xs text-gray-500 mt-1">
              Without email, pin will be deleted after 72 hours
            </p>
          </div>

          <Button
            onClick={() => generatePinMutation.mutate()}
            disabled={!coordinates || generatePinMutation.isPending}
            className="w-full bg-addypin-cyan hover:bg-cyan-600 text-white font-semibold py-4 px-6 rounded-lg transition-all duration-200 transform hover:scale-105 active:scale-95 shadow-lg hover:shadow-xl"
            data-testid="button-generate"
          >
            <AddyPinIcon className="mr-2" size={18} />
            {generatePinMutation.isPending ? "Generating..." : "Generate!"}
          </Button>
        </div>

        {generatedLink && (
          <div className={`mt-4 space-y-3 p-4 rounded-lg ${email ? 'bg-green-50 border border-green-200' : 'bg-gray-50 border border-gray-200'}`}>
            <h3 className={`text-sm font-semibold mb-3 ${email ? 'text-green-800' : 'text-gray-600'}`}>
              <i className="fas fa-check-circle mr-2"></i>
              {email ? 'Your addypin is ready!' : 'Sample addypin (expires in 72 hours)'}
            </h3>

            <div>
              <Label className={`block text-xs font-medium mb-1 ${email ? 'text-green-700' : 'text-gray-500'}`}>
                addypin link
              </Label>
              <div className={`flex items-center bg-white rounded-lg p-3 ${email ? 'border border-green-200' : 'border border-gray-300'}`}>
                <Input
                  type="text"
                  value={generatedLink.webLink}
                  readOnly
                  className={`flex-1 bg-transparent text-sm font-mono border-none p-0 focus-visible:ring-0 ${email ? 'text-addypin-dark' : 'text-gray-500'}`}
                  data-testid="input-web-link"
                />
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => copyToClipboard(generatedLink.webLink)}
                  className="ml-2 text-addypin-cyan hover:text-cyan-600 h-auto p-1"
                  data-testid="button-copy-web-link"
                >
                  <i className="fas fa-copy"></i>
                </Button>
              </div>
            </div>

            <div>
              <Label className={`block text-xs font-medium mb-1 ${email ? 'text-green-700' : 'text-gray-500'}`}>
                addypin email
              </Label>
              <div className={`flex items-center bg-white rounded-lg p-3 ${email ? 'border border-green-200' : 'border border-gray-300'}`}>
                <Input
                  type="text"
